-- FitGrant 시드 데이터 (65건) — schema.sql 실행 후 적재
-- 기준일 2026-06-13 · 자동 생성(data/programs.seed.json)

on conflict (id) do update set
  title=excluded.title, agency=excluded.agency, operator=excluded.operator,
  category=excluded.category, track=excluded.track, summary=excluded.summary,
  support_type=excluded.support_type, support_amount=excluded.support_amount,
  support_amount_max=excluded.support_amount_max, apply_start=excluded.apply_start,
  apply_end=excluded.apply_end, apply_cycle=excluded.apply_cycle, source_url=excluded.source_url,
  as_of_date=excluded.as_of_date, verification=excluded.verification,
  fashion_specific=excluded.fashion_specific, eligibility=excluded.eligibility;
